import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { adminAPI } from '../services/api';
import toast from 'react-hot-toast';
import {
  Users, Activity, List, ShieldAlert, MessageSquare,
  RefreshCw, Plus, Edit2, Trash2, Key, X, Check,
  TrendingUp, Server, DollarSign, Clock,
} from 'lucide-react';
import { format } from 'date-fns';

// ── small helpers ─────────────────────────────────────────────
const inp = {
  width:'100%', padding:'10px 12px', border:'1px solid #e2e8f0',
  borderRadius:'8px', fontSize:'14px', outline:'none',
  boxSizing:'border-box', background:'white', color:'#0f172a',
};

const TABS = [
  { id:'overview',   icon: TrendingUp,   label:'Overview'   },
  { id:'users',      icon: Users,        label:'Users'      },
  { id:'messages',   icon: MessageSquare,label:'Messages'   },
  { id:'optouts',    icon: ShieldAlert,  label:'Opt-Outs'   },
  { id:'audit',      icon: Activity,     label:'Audit Logs' },
  { id:'queue',      icon: Server,       label:'Queue'      },
];

const RoleBadge = ({ role }) => {
  const map = { admin:['#fef3c7','#92400e'], manager:['#dbeafe','#1e40af'], user:['#f1f5f9','#475569'] };
  const [bg, color] = map[role] || map.user;
  return <span style={{ padding:'2px 8px', borderRadius:'10px', background:bg, color, fontSize:'11px', fontWeight:700 }}>{role}</span>;
};

const StatusDot = ({ active }) => (
  <span style={{ display:'inline-flex', alignItems:'center', gap:'5px', fontSize:'12px', color: active ? '#16a34a' : '#dc2626' }}>
    <span style={{ width:'7px', height:'7px', borderRadius:'50%', background: active ? '#22c55e' : '#ef4444', display:'inline-block' }} />
    {active ? 'Active' : 'Inactive'}
  </span>
);

const MsgStatus = ({ s }) => {
  const map = { delivered:['#dcfce7','#166534'], sent:['#dbeafe','#1e40af'], failed:['#fee2e2','#991b1b'], queued:['#fef3c7','#92400e'], pending:['#f1f5f9','#475569'] };
  const [bg, color] = map[s] || map.pending;
  return <span style={{ padding:'2px 8px', borderRadius:'10px', background:bg, color, fontSize:'11px', fontWeight:700 }}>{s}</span>;
};

// ── Stat card ─────────────────────────────────────────────────
const StatBox = ({ label, value, sub, icon:Icon, color, bg }) => (
  <div style={{ background:'white', borderRadius:'12px', padding:'18px', border:'1px solid #f1f5f9', display:'flex', gap:'14px', alignItems:'flex-start' }}>
    <div style={{ width:'40px', height:'40px', borderRadius:'10px', background:bg, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
      <Icon size={18} color={color} />
    </div>
    <div>
      <div style={{ fontSize:'22px', fontWeight:700, color:'#0f172a', lineHeight:1 }}>{value ?? '—'}</div>
      <div style={{ fontSize:'12px', color:'#64748b', marginTop:'3px' }}>{label}</div>
      {sub && <div style={{ fontSize:'11px', color:'#94a3b8', marginTop:'2px' }}>{sub}</div>}
    </div>
  </div>
);

// ═════════════════════════════════════════════════════════════
export default function AdminPage() {
  const qc = useQueryClient();
  const [tab, setTab]         = useState('overview');
  const [showUserModal, setShowUserModal] = useState(false);
  const [editUser, setEditUser]   = useState(null);
  const [resetUserId, setResetUserId] = useState(null);
  const [userForm, setUserForm]   = useState({ name:'', email:'', password:'', role:'user' });
  const [newPass, setNewPass]     = useState('');
  const [msgSearch, setMsgSearch] = useState('');
  const [msgStatus, setMsgStatus] = useState('');
  const [auditPage, setAuditPage] = useState(1);
  const [msgPage, setMsgPage]     = useState(1);
  const [optPage, setOptPage]     = useState(1);

  // ── queries ──
  const { data: stats, isLoading: statsLoading, refetch: refetchStats } = useQuery({
    queryKey: ['admin-stats'],
    queryFn : () => adminAPI.getSystemStats().then(r => r.data.data),
    refetchInterval: 15000,
  });

  const { data: usersData } = useQuery({
    queryKey: ['admin-users'],
    queryFn : () => adminAPI.getUsers().then(r => r.data.data),
    enabled : tab === 'users',
  });

  const { data: auditData } = useQuery({
    queryKey: ['admin-audit', auditPage],
    queryFn : () => adminAPI.getAuditLogs({ page: auditPage, limit: 30 }).then(r => r.data),
    enabled : tab === 'audit',
  });

  const { data: msgData } = useQuery({
    queryKey: ['admin-messages', msgPage, msgStatus, msgSearch],
    queryFn : () => adminAPI.getMessages({ page: msgPage, limit: 40, status: msgStatus, search: msgSearch }).then(r => r.data),
    enabled : tab === 'messages',
  });

  const { data: optData } = useQuery({
    queryKey: ['admin-optouts', optPage],
    queryFn : () => adminAPI.getOptOuts({ page: optPage, limit: 40 }).then(r => r.data),
    enabled : tab === 'optouts',
  });

  // ── mutations ──
  const saveMutation = useMutation({
    mutationFn : (data) => editUser ? adminAPI.updateUser(editUser.id, data) : adminAPI.createUser(data),
    onSuccess  : () => { qc.invalidateQueries(['admin-users']); closeModal(); toast.success(editUser ? 'User updated!' : 'User created!'); },
    onError    : (e) => toast.error(e.response?.data?.message || 'Failed'),
  });

  const deleteMutation = useMutation({
    mutationFn : (id) => adminAPI.deleteUser(id),
    onSuccess  : () => { qc.invalidateQueries(['admin-users']); toast.success('User deleted'); },
    onError    : (e) => toast.error(e.response?.data?.message || 'Delete failed'),
  });

  const resetPassMutation = useMutation({
    mutationFn : () => adminAPI.resetPassword(resetUserId, { new_password: newPass }),
    onSuccess  : () => { setResetUserId(null); setNewPass(''); toast.success('Password reset!'); },
    onError    : (e) => toast.error(e.response?.data?.message || 'Reset failed'),
  });

  // ── helpers ──
  const openCreate = () => { setEditUser(null); setUserForm({ name:'', email:'', password:'', role:'user' }); setShowUserModal(true); };
  const openEdit   = (u)  => { setEditUser(u); setUserForm({ name:u.name, email:u.email, password:'', role:u.role }); setShowUserModal(true); };
  const closeModal = ()   => { setShowUserModal(false); setEditUser(null); };

  // ── tab content renderers ─────────────────────────────────

  const renderOverview = () => {
    const s = stats || {};
    return (
      <div>
        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'20px' }}>
          <h2 style={{ fontSize:'17px', fontWeight:700, color:'#0f172a' }}>System Overview</h2>
          <button onClick={() => refetchStats()} style={{ display:'flex', alignItems:'center', gap:'5px', padding:'7px 14px', background:'white', border:'1px solid #e2e8f0', borderRadius:'8px', cursor:'pointer', fontSize:'13px' }}>
            <RefreshCw size={13} /> Refresh
          </button>
        </div>
        {statsLoading ? <div style={{ color:'#94a3b8', textAlign:'center', padding:'40px' }}>Loading...</div> : (
          <>
            <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit, minmax(200px, 1fr))', gap:'14px', marginBottom:'20px' }}>
              <StatBox label="Total Users"      value={s.users?.total}     sub={`${s.users?.active} active`}      icon={Users}         color="#6366f1" bg="#eef2ff" />
              <StatBox label="Total Campaigns"  value={s.campaigns?.total} sub={`${s.campaigns?.running} running`} icon={TrendingUp}     color="#22c55e" bg="#dcfce7" />
              <StatBox label="Messages Sent"    value={parseInt(s.messages?.total||0).toLocaleString()} sub={`${s.messages?.last_24h} last 24h`} icon={MessageSquare} color="#3b82f6" bg="#dbeafe" />
              <StatBox label="Total Contacts"   value={parseInt(s.contacts?.total||0).toLocaleString()} sub={`${s.contacts?.opted_out} opted out`} icon={Users} color="#f59e0b" bg="#fef3c7" />
              <StatBox label="Total SMS Cost"   value={`$${parseFloat(s.messages?.total_cost||0).toFixed(4)}`} icon={DollarSign} color="#8b5cf6" bg="#f3e8ff" />
              <StatBox label="Twilio Balance"   value={s.twilio?.success ? `$${s.twilio.balance?.toFixed(2)} ${s.twilio.currency}` : 'N/A'} icon={DollarSign} color="#06b6d4" bg="#e0f2fe" />
            </div>

            {/* Queue stats */}
            <div style={{ background:'white', borderRadius:'12px', padding:'20px', border:'1px solid #f1f5f9' }}>
              <h3 style={{ fontSize:'15px', fontWeight:700, color:'#0f172a', marginBottom:'16px', display:'flex', alignItems:'center', gap:'8px' }}>
                <Server size={16} color="#6366f1" /> BullMQ Queue Status
              </h3>
              <div style={{ display:'flex', gap:'16px', flexWrap:'wrap' }}>
                {[
                  { label:'Waiting', value: s.queue?.waiting, color:'#f59e0b' },
                  { label:'Active',  value: s.queue?.active,  color:'#3b82f6' },
                  { label:'Completed',value:s.queue?.completed,color:'#22c55e' },
                  { label:'Failed',  value: s.queue?.failed,  color:'#ef4444' },
                  { label:'Delayed', value: s.queue?.delayed, color:'#8b5cf6' },
                ].map(q => (
                  <div key={q.label} style={{ textAlign:'center', padding:'14px 20px', borderRadius:'10px', background:'#f8fafc', minWidth:'90px' }}>
                    <div style={{ fontSize:'22px', fontWeight:700, color: q.color }}>{q.value ?? 0}</div>
                    <div style={{ fontSize:'12px', color:'#64748b', marginTop:'4px' }}>{q.label}</div>
                  </div>
                ))}
              </div>
            </div>
          </>
        )}
      </div>
    );
  };

  const renderUsers = () => (
    <div>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'20px' }}>
        <h2 style={{ fontSize:'17px', fontWeight:700, color:'#0f172a' }}>User Management</h2>
        <button onClick={openCreate} style={{ display:'flex', alignItems:'center', gap:'6px', padding:'9px 18px', background:'linear-gradient(135deg,#6366f1,#8b5cf6)', border:'none', borderRadius:'8px', color:'white', fontWeight:600, cursor:'pointer', fontSize:'13px' }}>
          <Plus size={14} /> Add User
        </button>
      </div>
      <div style={{ background:'white', borderRadius:'12px', border:'1px solid #f1f5f9', overflow:'hidden' }}>
        <table style={{ width:'100%', borderCollapse:'collapse' }}>
          <thead>
            <tr style={{ borderBottom:'1px solid #f1f5f9' }}>
              {['Name','Email','Role','Status','Campaigns','Contacts','Last Login','Actions'].map(h => (
                <th key={h} style={{ padding:'10px 14px', textAlign:'left', fontSize:'12px', fontWeight:600, color:'#94a3b8' }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {(usersData||[]).map(u => (
              <tr key={u.id} style={{ borderBottom:'1px solid #f8fafc' }}>
                <td style={{ padding:'12px 14px', fontWeight:600, fontSize:'14px', color:'#0f172a' }}>{u.name}</td>
                <td style={{ padding:'12px 14px', fontSize:'13px', color:'#64748b' }}>{u.email}</td>
                <td style={{ padding:'12px 14px' }}><RoleBadge role={u.role} /></td>
                <td style={{ padding:'12px 14px' }}><StatusDot active={u.is_active} /></td>
                <td style={{ padding:'12px 14px', fontSize:'13px', color:'#374151' }}>{u.campaign_count||0}</td>
                <td style={{ padding:'12px 14px', fontSize:'13px', color:'#374151' }}>{u.contact_count||0}</td>
                <td style={{ padding:'12px 14px', fontSize:'12px', color:'#94a3b8' }}>
                  {u.last_login ? format(new Date(u.last_login), 'MMM dd, HH:mm') : 'Never'}
                </td>
                <td style={{ padding:'12px 14px' }}>
                  <div style={{ display:'flex', gap:'5px' }}>
                    <button onClick={() => openEdit(u)} title="Edit" style={{ padding:'5px', background:'#fef3c7', border:'none', borderRadius:'5px', cursor:'pointer', color:'#d97706' }}><Edit2 size={13} /></button>
                    <button onClick={() => setResetUserId(u.id)} title="Reset password" style={{ padding:'5px', background:'#dbeafe', border:'none', borderRadius:'5px', cursor:'pointer', color:'#2563eb' }}><Key size={13} /></button>
                    <button onClick={() => { if(window.confirm('Delete user?')) deleteMutation.mutate(u.id); }} title="Delete" style={{ padding:'5px', background:'#fee2e2', border:'none', borderRadius:'5px', cursor:'pointer', color:'#dc2626' }}><Trash2 size={13} /></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  const renderMessages = () => (
    <div>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'16px', flexWrap:'wrap', gap:'10px' }}>
        <h2 style={{ fontSize:'17px', fontWeight:700, color:'#0f172a' }}>Messages Log</h2>
        <div style={{ display:'flex', gap:'10px' }}>
          <input placeholder="Search number or text..." value={msgSearch}
            onChange={e => { setMsgSearch(e.target.value); setMsgPage(1); }}
            style={{ ...inp, width:'220px' }} />
          <select value={msgStatus} onChange={e => { setMsgStatus(e.target.value); setMsgPage(1); }}
            style={{ ...inp, width:'auto', cursor:'pointer' }}>
            <option value="">All Status</option>
            {['queued','sent','delivered','failed','pending'].map(s => <option key={s} value={s}>{s}</option>)}
          </select>
        </div>
      </div>
      <div style={{ background:'white', borderRadius:'12px', border:'1px solid #f1f5f9', overflow:'hidden' }}>
        <table style={{ width:'100%', borderCollapse:'collapse' }}>
          <thead>
            <tr style={{ borderBottom:'1px solid #f1f5f9' }}>
              {['To','From','Status','Campaign','Message','Cost','Sent At'].map(h => (
                <th key={h} style={{ padding:'10px 14px', textAlign:'left', fontSize:'12px', fontWeight:600, color:'#94a3b8' }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {(msgData?.data||[]).length === 0 ? (
              <tr><td colSpan={7} style={{ padding:'40px', textAlign:'center', color:'#94a3b8' }}>No messages found</td></tr>
            ) : (msgData?.data||[]).map(m => (
              <tr key={m.id} style={{ borderBottom:'1px solid #f8fafc' }}>
                <td style={{ padding:'10px 14px', fontFamily:'monospace', fontSize:'13px', color:'#0f172a' }}>{m.to_number}</td>
                <td style={{ padding:'10px 14px', fontFamily:'monospace', fontSize:'12px', color:'#64748b' }}>{m.from_number||'—'}</td>
                <td style={{ padding:'10px 14px' }}><MsgStatus s={m.status} /></td>
                <td style={{ padding:'10px 14px', fontSize:'12px', color:'#6366f1', fontWeight:500 }}>{m.campaign_name||'—'}</td>
                <td style={{ padding:'10px 14px', fontSize:'12px', color:'#374151', maxWidth:'200px', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}
                    title={m.message_text}>{m.message_text}</td>
                <td style={{ padding:'10px 14px', fontSize:'12px', color:'#64748b' }}>
                  {m.cost ? `$${parseFloat(m.cost).toFixed(5)}` : '—'}
                </td>
                <td style={{ padding:'10px 14px', fontSize:'12px', color:'#94a3b8' }}>
                  {m.sent_at ? format(new Date(m.sent_at), 'MMM dd HH:mm') : '—'}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {/* Pagination */}
        {msgData?.pagination && (
          <div style={{ padding:'12px 16px', borderTop:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', alignItems:'center', fontSize:'13px', color:'#64748b' }}>
            <span>Total: {msgData.pagination.total?.toLocaleString()} messages</span>
            <div style={{ display:'flex', gap:'6px' }}>
              <button onClick={() => setMsgPage(p => Math.max(1,p-1))} disabled={msgPage===1}
                style={{ padding:'5px 12px', border:'1px solid #e2e8f0', borderRadius:'6px', background:'white', cursor:'pointer', fontSize:'12px' }}>← Prev</button>
              <span style={{ padding:'5px 10px', fontSize:'12px' }}>Page {msgPage}</span>
              <button onClick={() => setMsgPage(p => p+1)} disabled={msgData.data?.length < 40}
                style={{ padding:'5px 12px', border:'1px solid #e2e8f0', borderRadius:'6px', background:'white', cursor:'pointer', fontSize:'12px' }}>Next →</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );

  const renderOptOuts = () => (
    <div>
      <div style={{ marginBottom:'16px' }}>
        <h2 style={{ fontSize:'17px', fontWeight:700, color:'#0f172a' }}>Opt-Out Log</h2>
        <p style={{ color:'#64748b', fontSize:'13px', marginTop:'4px' }}>Contacts who replied STOP/UNSUBSCRIBE</p>
      </div>
      <div style={{ background:'white', borderRadius:'12px', border:'1px solid #f1f5f9', overflow:'hidden' }}>
        <table style={{ width:'100%', borderCollapse:'collapse' }}>
          <thead>
            <tr style={{ borderBottom:'1px solid #f1f5f9' }}>
              {['Phone','Name','Source','Reason','Raw Message','Date'].map(h => (
                <th key={h} style={{ padding:'10px 14px', textAlign:'left', fontSize:'12px', fontWeight:600, color:'#94a3b8' }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {(optData?.data||[]).length === 0 ? (
              <tr><td colSpan={6} style={{ padding:'40px', textAlign:'center', color:'#94a3b8' }}>No opt-outs recorded yet</td></tr>
            ) : (optData?.data||[]).map(o => (
              <tr key={o.id} style={{ borderBottom:'1px solid #f8fafc' }}>
                <td style={{ padding:'10px 14px', fontFamily:'monospace', fontSize:'13px', fontWeight:600, color:'#0f172a' }}>{o.phone}</td>
                <td style={{ padding:'10px 14px', fontSize:'13px', color:'#374151' }}>
                  {[o.first_name, o.last_name].filter(Boolean).join(' ') || '—'}
                </td>
                <td style={{ padding:'10px 14px' }}>
                  <span style={{ padding:'2px 8px', borderRadius:'10px', background:'#fee2e2', color:'#dc2626', fontSize:'11px', fontWeight:700 }}>{o.source}</span>
                </td>
                <td style={{ padding:'10px 14px', fontSize:'12px', color:'#64748b' }}>{o.reason||'—'}</td>
                <td style={{ padding:'10px 14px', fontSize:'12px', color:'#94a3b8', fontFamily:'monospace' }}>{o.raw_message||'—'}</td>
                <td style={{ padding:'10px 14px', fontSize:'12px', color:'#94a3b8' }}>
                  {o.processed_at ? format(new Date(o.processed_at), 'MMM dd, yyyy HH:mm') : '—'}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {optData?.pagination && (
          <div style={{ padding:'12px 16px', borderTop:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', fontSize:'13px', color:'#64748b' }}>
            <span>Total: {optData.pagination.total?.toLocaleString()} opt-outs</span>
            <div style={{ display:'flex', gap:'6px' }}>
              <button onClick={() => setOptPage(p => Math.max(1,p-1))} disabled={optPage===1}
                style={{ padding:'5px 12px', border:'1px solid #e2e8f0', borderRadius:'6px', background:'white', cursor:'pointer', fontSize:'12px' }}>← Prev</button>
              <span style={{ padding:'5px 10px', fontSize:'12px' }}>Page {optPage}</span>
              <button onClick={() => setOptPage(p => p+1)} disabled={optData.data?.length < 40}
                style={{ padding:'5px 12px', border:'1px solid #e2e8f0', borderRadius:'6px', background:'white', cursor:'pointer', fontSize:'12px' }}>Next →</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );

  const renderAudit = () => (
    <div>
      <div style={{ marginBottom:'16px' }}>
        <h2 style={{ fontSize:'17px', fontWeight:700, color:'#0f172a' }}>Audit Logs</h2>
        <p style={{ color:'#64748b', fontSize:'13px', marginTop:'4px' }}>All user actions tracked automatically</p>
      </div>
      <div style={{ background:'white', borderRadius:'12px', border:'1px solid #f1f5f9', overflow:'hidden' }}>
        <table style={{ width:'100%', borderCollapse:'collapse' }}>
          <thead>
            <tr style={{ borderBottom:'1px solid #f1f5f9' }}>
              {['User','Action','Resource','IP Address','Time'].map(h => (
                <th key={h} style={{ padding:'10px 14px', textAlign:'left', fontSize:'12px', fontWeight:600, color:'#94a3b8' }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {(auditData?.data||[]).length === 0 ? (
              <tr><td colSpan={5} style={{ padding:'40px', textAlign:'center', color:'#94a3b8' }}>No audit logs yet</td></tr>
            ) : (auditData?.data||[]).map(a => (
              <tr key={a.id} style={{ borderBottom:'1px solid #f8fafc' }}>
                <td style={{ padding:'10px 14px' }}>
                  <div style={{ fontSize:'13px', fontWeight:600, color:'#0f172a' }}>{a.user_name||'System'}</div>
                  <div style={{ fontSize:'11px', color:'#94a3b8' }}>{a.user_email}</div>
                </td>
                <td style={{ padding:'10px 14px' }}>
                  <span style={{ padding:'2px 8px', borderRadius:'6px', background:'#eef2ff', color:'#6366f1', fontSize:'11px', fontWeight:700, fontFamily:'monospace' }}>
                    {a.action}
                  </span>
                </td>
                <td style={{ padding:'10px 14px', fontSize:'12px', color:'#64748b' }}>
                  {a.resource} {a.resource_id ? <span style={{ color:'#94a3b8', fontFamily:'monospace' }}>#{a.resource_id?.slice(0,8)}</span> : ''}
                </td>
                <td style={{ padding:'10px 14px', fontFamily:'monospace', fontSize:'12px', color:'#94a3b8' }}>{a.ip_address||'—'}</td>
                <td style={{ padding:'10px 14px', fontSize:'12px', color:'#94a3b8' }}>
                  {a.created_at ? format(new Date(a.created_at), 'MMM dd HH:mm:ss') : '—'}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {auditData?.pagination && (
          <div style={{ padding:'12px 16px', borderTop:'1px solid #f1f5f9', display:'flex', justifyContent:'space-between', fontSize:'13px', color:'#64748b' }}>
            <span>Total: {auditData.pagination.total?.toLocaleString()} entries</span>
            <div style={{ display:'flex', gap:'6px' }}>
              <button onClick={() => setAuditPage(p => Math.max(1,p-1))} disabled={auditPage===1}
                style={{ padding:'5px 12px', border:'1px solid #e2e8f0', borderRadius:'6px', background:'white', cursor:'pointer', fontSize:'12px' }}>← Prev</button>
              <span style={{ padding:'5px 10px', fontSize:'12px' }}>Page {auditPage}</span>
              <button onClick={() => setAuditPage(p => p+1)} disabled={auditData.data?.length < 30}
                style={{ padding:'5px 12px', border:'1px solid #e2e8f0', borderRadius:'6px', background:'white', cursor:'pointer', fontSize:'12px' }}>Next →</button>
            </div>
          </div>
        )}
      </div>
    </div>
  );

  const renderQueue = () => {
    const q = stats?.queue || {};
    return (
      <div>
        <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'20px' }}>
          <div>
            <h2 style={{ fontSize:'17px', fontWeight:700, color:'#0f172a' }}>BullMQ Queue Monitor</h2>
            <p style={{ color:'#64748b', fontSize:'13px', marginTop:'4px' }}>Real-time SMS sending queue status</p>
          </div>
          <button onClick={() => refetchStats()} style={{ display:'flex', alignItems:'center', gap:'5px', padding:'7px 14px', background:'white', border:'1px solid #e2e8f0', borderRadius:'8px', cursor:'pointer', fontSize:'13px' }}>
            <RefreshCw size={13} /> Refresh
          </button>
        </div>
        <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit, minmax(160px, 1fr))', gap:'14px', marginBottom:'24px' }}>
          {[
            { label:'Waiting',   value:q.waiting,   color:'#f59e0b', bg:'#fef3c7',  desc:'Ready to process' },
            { label:'Active',    value:q.active,    color:'#3b82f6', bg:'#dbeafe',  desc:'Being sent now'   },
            { label:'Completed', value:q.completed, color:'#22c55e', bg:'#dcfce7',  desc:'Successfully sent' },
            { label:'Failed',    value:q.failed,    color:'#ef4444', bg:'#fee2e2',  desc:'Delivery failed'  },
            { label:'Delayed',   value:q.delayed,   color:'#8b5cf6', bg:'#f3e8ff',  desc:'Scheduled future' },
          ].map(item => (
            <div key={item.label} style={{ background:'white', borderRadius:'12px', padding:'18px', border:'1px solid #f1f5f9', textAlign:'center' }}>
              <div style={{ fontSize:'32px', fontWeight:800, color:item.color }}>{item.value ?? 0}</div>
              <div style={{ fontSize:'13px', fontWeight:700, color:'#0f172a', marginTop:'4px' }}>{item.label}</div>
              <div style={{ fontSize:'11px', color:'#94a3b8', marginTop:'2px' }}>{item.desc}</div>
            </div>
          ))}
        </div>
        <div style={{ background:'white', borderRadius:'12px', padding:'20px', border:'1px solid #f1f5f9' }}>
          <h3 style={{ fontSize:'14px', fontWeight:700, color:'#0f172a', marginBottom:'12px' }}>Queue Configuration</h3>
          <div style={{ display:'grid', gap:'8px', fontSize:'13px' }}>
            {[
              ['Worker Concurrency', '10 messages simultaneously'],
              ['Rate Limit', '10 SMS per second (Twilio safe)'],
              ['Max Retries', '3 attempts per message'],
              ['Retry Strategy', 'Exponential backoff (3s, 6s, 12s)'],
              ['Queue Name', 'sms-sending'],
              ['Redis Connection', `${process.env.REACT_APP_REDIS_HOST || 'localhost'}:6379`],
            ].map(([k, v]) => (
              <div key={k} style={{ display:'flex', justifyContent:'space-between', padding:'8px 12px', background:'#f8fafc', borderRadius:'6px' }}>
                <span style={{ color:'#64748b', fontWeight:500 }}>{k}</span>
                <span style={{ color:'#0f172a', fontFamily:'monospace', fontSize:'12px' }}>{v}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    );
  };

  const tabContent = {
    overview : renderOverview,
    users    : renderUsers,
    messages : renderMessages,
    optouts  : renderOptOuts,
    audit    : renderAudit,
    queue    : renderQueue,
  };

  // ═══════════════════════════════════════════════
  return (
    <div style={{ padding:'32px', background:'#f8fafc', minHeight:'100vh' }}>

      {/* Page header */}
      <div style={{ marginBottom:'28px' }}>
        <h1 style={{ fontSize:'24px', fontWeight:700, color:'#0f172a' }}>Admin Panel</h1>
        <p style={{ color:'#64748b', marginTop:'4px' }}>System management and monitoring</p>
      </div>

      {/* Tab nav */}
      <div style={{ display:'flex', gap:'4px', marginBottom:'24px', background:'white', padding:'6px', borderRadius:'12px', border:'1px solid #f1f5f9', flexWrap:'wrap' }}>
        {TABS.map(t => {
          const Icon = t.icon;
          const active = tab === t.id;
          return (
            <button key={t.id} onClick={() => setTab(t.id)} style={{
              display:'flex', alignItems:'center', gap:'6px',
              padding:'8px 14px', borderRadius:'8px', border:'none', cursor:'pointer',
              background: active ? 'linear-gradient(135deg,#6366f1,#8b5cf6)' : 'transparent',
              color: active ? 'white' : '#64748b',
              fontWeight: active ? 600 : 400, fontSize:'13px', transition:'all 0.2s',
            }}>
              <Icon size={14} />{t.label}
            </button>
          );
        })}
      </div>

      {/* Tab content */}
      {tabContent[tab]?.()}

      {/* ── Create/Edit User Modal ── */}
      {showUserModal && (
        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', zIndex:1000, display:'flex', alignItems:'center', justifyContent:'center', padding:'20px' }}>
          <div style={{ background:'white', borderRadius:'20px', padding:'32px', width:'100%', maxWidth:'480px' }}>
            <div style={{ display:'flex', justifyContent:'space-between', marginBottom:'24px' }}>
              <h2 style={{ fontSize:'20px', fontWeight:700, color:'#0f172a' }}>{editUser ? 'Edit User' : 'Create User'}</h2>
              <button onClick={closeModal} style={{ background:'none', border:'none', cursor:'pointer', color:'#94a3b8' }}><X size={20} /></button>
            </div>
            <form onSubmit={e => { e.preventDefault(); saveMutation.mutate(userForm); }}>
              <div style={{ display:'grid', gap:'14px' }}>
                <div>
                  <label style={{ display:'block', fontSize:'13px', fontWeight:600, marginBottom:'5px' }}>Full Name *</label>
                  <input style={inp} value={userForm.name} onChange={e => setUserForm({...userForm, name:e.target.value})} required />
                </div>
                <div>
                  <label style={{ display:'block', fontSize:'13px', fontWeight:600, marginBottom:'5px' }}>Email *</label>
                  <input type="email" style={inp} value={userForm.email} onChange={e => setUserForm({...userForm, email:e.target.value})} required disabled={!!editUser} />
                </div>
                {!editUser && (
                  <div>
                    <label style={{ display:'block', fontSize:'13px', fontWeight:600, marginBottom:'5px' }}>Password *</label>
                    <input type="password" style={inp} value={userForm.password} onChange={e => setUserForm({...userForm, password:e.target.value})} required minLength={6} />
                  </div>
                )}
                <div>
                  <label style={{ display:'block', fontSize:'13px', fontWeight:600, marginBottom:'5px' }}>Role</label>
                  <select style={{ ...inp, cursor:'pointer' }} value={userForm.role} onChange={e => setUserForm({...userForm, role:e.target.value})}>
                    <option value="user">User</option>
                    <option value="manager">Manager</option>
                    <option value="admin">Admin</option>
                  </select>
                </div>
                {editUser && (
                  <div>
                    <label style={{ display:'block', fontSize:'13px', fontWeight:600, marginBottom:'5px' }}>Status</label>
                    <select style={{ ...inp, cursor:'pointer' }} value={userForm.is_active} onChange={e => setUserForm({...userForm, is_active: e.target.value === 'true'})}>
                      <option value="true">Active</option>
                      <option value="false">Inactive</option>
                    </select>
                  </div>
                )}
              </div>
              <div style={{ display:'flex', gap:'10px', marginTop:'24px', justifyContent:'flex-end' }}>
                <button type="button" onClick={closeModal} style={{ padding:'9px 18px', border:'1px solid #e2e8f0', borderRadius:'8px', background:'white', cursor:'pointer', fontWeight:500 }}>Cancel</button>
                <button type="submit" disabled={saveMutation.isPending} style={{ padding:'9px 20px', background:'linear-gradient(135deg,#6366f1,#8b5cf6)', border:'none', borderRadius:'8px', color:'white', fontWeight:600, cursor:'pointer' }}>
                  {saveMutation.isPending ? 'Saving...' : (editUser ? 'Update' : 'Create User')}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* ── Reset Password Modal ── */}
      {resetUserId && (
        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.5)', zIndex:1000, display:'flex', alignItems:'center', justifyContent:'center', padding:'20px' }}>
          <div style={{ background:'white', borderRadius:'20px', padding:'28px', width:'100%', maxWidth:'400px' }}>
            <div style={{ display:'flex', justifyContent:'space-between', marginBottom:'20px' }}>
              <h3 style={{ fontSize:'18px', fontWeight:700, color:'#0f172a' }}>Reset Password</h3>
              <button onClick={() => { setResetUserId(null); setNewPass(''); }} style={{ background:'none', border:'none', cursor:'pointer', color:'#94a3b8' }}><X size={18} /></button>
            </div>
            <div style={{ marginBottom:'20px' }}>
              <label style={{ display:'block', fontSize:'13px', fontWeight:600, marginBottom:'6px' }}>New Password</label>
              <input type="password" style={inp} value={newPass} onChange={e => setNewPass(e.target.value)} placeholder="Min 6 characters" minLength={6} />
            </div>
            <div style={{ display:'flex', gap:'10px', justifyContent:'flex-end' }}>
              <button onClick={() => { setResetUserId(null); setNewPass(''); }} style={{ padding:'9px 18px', border:'1px solid #e2e8f0', borderRadius:'8px', background:'white', cursor:'pointer', fontWeight:500 }}>Cancel</button>
              <button onClick={() => { if(newPass.length >= 6) resetPassMutation.mutate(); else toast.error('Min 6 characters'); }}
                disabled={resetPassMutation.isPending}
                style={{ padding:'9px 20px', background:'#dc2626', border:'none', borderRadius:'8px', color:'white', fontWeight:600, cursor:'pointer' }}>
                {resetPassMutation.isPending ? 'Resetting...' : 'Reset Password'}
              </button>
            </div>
          </div>
        </div>
      )}

    </div>
  );
}
